    return median

def get_median(a, b, n):
    # If one of the arrays is empty, return the other's median
    if len(a) == 0:
        return b[n // 2]
    if len(b) == 0:
        return a[n // 2]

    # Initialize pointers
    left, right = 0, len(a)
    while left < right:
        mid = (left + right) // 2
        mid_2 = n - mid - 1

        # Check if we have found the correct split
        if a[mid] <= b[mid_2 + 1] and b[mid_2] <= a[mid + 1]:
            # If odd, return the middle element
            if n % 2 == 1:
                return max(a[mid], b[mid_2])
            # If even, return the average of the two middle elements
            else:
                return (max(a[mid], b[mid_2]) + min(a[mid + 1], b[mid_2 + 1])) / 2
        # Move the pointers based on the comparison results
        elif a[mid] > b[mid_2 + 1]:
            right = mid
        else:
            left = mid + 1

