    mid = (n + 1) // 2
    med1, med2 = 0, 0

    while i < n and j < n:
        if nums1[i] <= nums2[j]:
            med1, med2 = med2, nums1[i]
            i += 1
        else:
            med1, med2 = med2, nums2[j]
            j += 1

        if (i + j) == mid:
            break

    if i == n:
        med1 = med2
        med2 = nums2[j + mid - (i + j)]
    elif j == n:
        med1 = med2
        med2 = nums1[i + mid - (i + j)]

