def maxAverageOfPath(costs):
    n = len(costs)
    for i in range(1, n):
        costs[i][0] += costs[i - 1][0]
    for i in range(1, n):
        costs[0][i] += costs[0][i - 1]

    for i in range(1, n):
        for j in range(1, n):
            costs[i][j] += max(costs[i - 1][j], costs[i][j - 1])

    return (costs[n - 1][n - 1]) / (n * n)

def maxAverageOfPath(matrix):
    # Initialize the maximum average and starting point
    max_avg = -float('inf')
    start_row, start_col = 0, 0

    # Iterate through all possible starting points
    for i in range(len(matrix)):
        for j in range(len(matrix[i])):
            # Start BFS from the current point
            queue = [(i, j)]
            total_cost = 0
            num_cells = 0

            while queue:
                x, y = queue.pop(0)
                total_cost += matrix[x][y]
                num_cells += 1

                # Check if we've reached the bottom-right corner
                if x == len(matrix) - 1 and y == len(matrix[0]) - 1:
                    avg = total_cost / num_cells
                    if avg > max_avg:
                        max_avg = avg
                        start_row, start_col = x, y
                else:
                    # Add neighboring cells to the queue
                    if x < len(matrix) - 1:
                        queue.append((x + 1, y))
                    if y < len(matrix[0]) - 1:
                        queue.append((x, y + 1))

    return max_avg

def maxAverageOfPath(A):
    N = len(A)
    dp = [[0 for _ in range(N)] for _ in range(N)]

    # Initialize first row and first column
    for i in range(N):
        dp[0][i] = (dp[0][i - 1] + A[0][i]) / (i + 1)
        dp[i][0] = (dp[i - 1][0] + A[i][0]) / (i + 1)

    # Fill the dp table
    for i in range(1, N):
        for j in range(1, N):
            dp[i][j] = max((dp[i - 1][j] + A[i][j]) / (j + 1), 
                          (dp[i][j - 1] + A[i][j]) / (i + 1))

    return dp[N - 1][N - 1]

