    df = mx - mn

    if mx == mn:
        H = 0
    elif mx == R:
        H = (60 * ((G - B) / df) + 360) % 360
    elif mx == G:
        H = (60 * ((B - R) / df) + 120) % 360
    elif mx == B:
        H = (60 * ((R - G) / df) + 240) % 360

    if mx == 0:
        S = 0
    else:
        S = (df / mx) * 100

    V = mx * 100
    return H, S, V

